import type { ReactElement } from 'react';
import type { TabProps } from './Tab';
import type { CurrentTabData } from './Tab/Tab.types';
/**
 * данные, нужные для отрисовки табов
 */
interface UseTabsData {
    /**
     * контент, который необходимо отрисовать для выбранного таба
     */
    currentTabData: CurrentTabData;
    /**
     * индекс выбранного таба, может быть нужен в компоненте для побочных эффектов, например для анимации индикатора
     */
    currentTabIndex: number;
    prevTabData: CurrentTabData;
    /**
     * массив готовых к отрисовке компонентов Tab,
     * остается только положить их в контейнер, который выберет родитель,
     * например для вертикальной и горизонтальной отрисовки будут разные контейнеры, но один набор компонентов Tab
     */
    tabs: Array<ReactElement<TabProps>>;
}
/**
 * инкапсулирует логику управления табами
 *
 * Работает так
 *
 * 1. changeTab - функция для переключения табов (переключай табы только ей), должна содержать в себе все вызовы, нужные при успешной смене таба
 * 2. enrichedTabs - массив компонентов Tab (передается ребенком в компонент), обогащенный данными из родителя. Это данные selected, реакция на клик и т.д
 * 3. body - тело текущей страницы. Ищет текущий выбранный таб и возвращает его children-a
 *
 * useEffect-ы в конце отвечают за управление выбранным табом "снаружи" и изначальную отрисовку доступного таба (чтобы при первом рендере не отрисовать контент задизейбленного таба)
 *
 * @returns данные нужные для отрисовки табов. Читай описание {@link UseTabsData}
 */
export declare const useTabs: ({ onChange, selectedTabIndex, tabs }: {
    onChange: any;
    selectedTabIndex: any;
    tabs: any;
}) => UseTabsData;
export {};
